import React, { useEffect, useState } from "react";
import "./App.css";

function App() {
  const API_URL = "http://localhost:5000/api/reports";

  const [view, setView] = useState("home"); // home | form
  const [loading, setLoading] = useState(false);
  const [reports, setReports] = useState([]);

  // -------------------------------
  // CARGAR REPORTES DESDE EL BACKEND
  // -------------------------------
  const fetchReports = async () => {
    try {
      setLoading(true);
      const res = await fetch(API_URL);
      const data = await res.json();
      setReports(data);
    } catch (error) {
      alert("No se pudieron cargar los reportes desde el servidor.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchReports();
  }, []);

  // -------------------------------
  // FORMULARIO: CAMPOS
  // -------------------------------
  const [type, setType] = useState("Basura acumulada");
  const [description, setDescription] = useState("");
  const [location, setLocation] = useState("");
  const [contact, setContact] = useState("");
  const [priority, setPriority] = useState("media");
  const [zone, setZone] = useState("");

  // -------------------------------
  // ENVIAR REPORTE AL SERVIDOR
  // -------------------------------
  const submitReport = async (e) => {
    e.preventDefault();

    try {
      const res = await fetch(API_URL, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          type,
          description,
          location,
          contact,
          priority,
          zone,
        }),
      });

      if (!res.ok) throw new Error("Error al enviar reporte");

      alert("Reporte registrado en el servidor.");

      // Recargar lista
      fetchReports();
      setView("home");
    } catch (error) {
      alert("Hubo un problema al registrar el reporte.");
    }
  };

  // -------------------------------
  // RENDER: PÁGINA PRINCIPAL
// -------------------------------
const renderHome = () => {
  return (

    <main style={{ padding: "20px" }}>

      {/* HERO */}
      <section
        style={{
          padding: "40px 20px",
          textAlign: "center",
          borderBottom: "3px solid #900",
          marginBottom: "25px",
        }}
      >
        <h1 style={{ color: "#900", fontSize: "42px", fontWeight: "bold" }}>
          ¡BALBOA ALERTA ESTÁ VIVO!
        </h1>
        <p style={{ fontSize: "18px", marginTop: "10px" }}>
          Vecinos organizados reportando basura, daños, riesgos y problemas en
          tiempo real. Un distrito más limpio, más seguro, más nuestro.
        </p>

        <button
          onClick={() => setView("form")}
          style={{
            marginTop: "25px",
            backgroundColor: "#b30000",
            color: "white",
            padding: "15px 40px",
            borderRadius: "30px",
            border: "none",
            fontSize: "20px",
            cursor: "pointer",
          }}
        >
          Reportar incidencia
        </button>
      </section>

      {/* TABLERO DE ESTADÍSTICAS */}
      <section style={{ marginBottom: "25px" }}>
        <h2 style={{ fontSize: "22px", marginBottom: "10px" }}>
          Reportes recientes
        </h2>

        <div>
          {loading ? (
            <p>Cargando...</p>
          ) : reports.length === 0 ? (
            <p>Aún no hay reportes registrados.</p>
          ) : (
            reports.map((r) => (
              <div
                key={r.id}
                style={{
                  border: "1px solid #ddd",
                  borderLeft: "5px solid #cc0000",
                  marginBottom: "15px",
                  padding: "15px",
                  borderRadius: "6px",
                  background: "#fff",
                }}
              >
                <h3 style={{ margin: 0 }}>{r.type}</h3>

                <p>
                  <strong>Prioridad:</strong>{" "}
                  <span style={{ color: "#c60" }}>{r.priority}</span>{" "}
                  &nbsp;|&nbsp; <strong>Estado:</strong>{" "}
                  <span style={{ color: "#090" }}>{r.status}</span>
                </p>

                <p>{r.description}</p>

                <p>
                  <strong>Ubicación:</strong> {r.location}
                </p>

                {r.contact && (
                  <p>
                    <strong>Contacto:</strong> {r.contact}
                  </p>
                )}

                <p style={{ fontSize: "12px", color: "#555" }}>
                  {new Date(r.createdAt).toLocaleString()}
                </p>
              </div>
            ))
          )}
        </div>
      </section>

    </main>
    );
};

  // -------------------------------
  // RENDER: FORMULARIO DE REPORTE
  // -------------------------------
  const renderReportForm = () => (
    <main style={{ padding: "20px" }}>
      <h2>Nuevo reporte ciudadano</h2>

      <form onSubmit={submitReport} style={{ maxWidth: "500px" }}>

        <label>Tipo de incidencia *</label>
        <select
          value={type}
          onChange={(e) => setType(e.target.value)}
          required
          style={{ width: "100%", padding: "10px", marginBottom: "15px" }}
        >
          <option>Basura acumulada</option>
          <option>Alumbrado defectuoso</option>
          <option>Drenajes tapados</option>
          <option>Daño en vía pública</option>
          <option>Riesgo para peatones</option>
          <option>Agua estancada</option>
        </select>

        <label>Descripción *</label>
        <textarea
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          required
          style={{ width: "100%", padding: "10px", marginBottom: "15px" }}
        />

        <label>Ubicación aproximada *</label>
        <input
          value={location}
          onChange={(e) => setLocation(e.target.value)}
          required
          style={{ width: "100%", padding: "10px", marginBottom: "15px" }}
        />

        <label>Contacto (opcional)</label>
        <input
          value={contact}
          onChange={(e) => setContact(e.target.value)}
          style={{ width: "100%", padding: "10px", marginBottom: "15px" }}
        />

        <label>Prioridad</label>
        <select
          value={priority}
          onChange={(e) => setPriority(e.target.value)}
          style={{ width: "100%", padding: "10px", marginBottom: "15px" }}
        >
          <option value="critica">Crítica</option>
          <option value="alta">Alta</option>
          <option value="media">Media</option>
          <option value="baja">Baja</option>
        </select>

        <label>Zona / Sector</label>
        <input
          value={zone}
          onChange={(e) => setZone(e.target.value)}
          style={{ width: "100%", padding: "10px", marginBottom: "15px" }}
        />

        <button
          type="submit"
          style={{
            backgroundColor: "#b30000",
            color: "white",
            padding: "12px 25px",
            border: "none",
            borderRadius: "8px",
            cursor: "pointer",
          }}
        >
          Enviar reporte
        </button>

        <button
          type="button"
          onClick={() => setView("home")}
          style={{
            marginLeft: "10px",
            padding: "12px 25px",
            borderRadius: "8px",
            border: "1px solid #555",
            cursor: "pointer",
          }}
        >
          Cancelar
        </button>
      </form>
    </main>
  );

  // -------------------------------
  // RENDER FINAL
  // -------------------------------
  return view === "home" ? renderHome() : renderReportForm();
}

export default App;
